import time

class LoggerRateLimiter:
    def __init__(self):
        self._last_logged_time = {}

    def log(self, message: str, cooldown_seconds: float, key: str = None) -> bool:
        current_time = time.time()
        log_key = key if key is not None else message

        if log_key not in self._last_logged_time or \
           (current_time - self._last_logged_time[log_key]) >= cooldown_seconds:
            print(f"Logged: {message}")  # Replace with actual logging mechanism (e.g., logging.info(message))
            self._last_logged_time[log_key] = current_time
            return True
        return False
